SELECT POHD.PO_NUM , POHD.SUBJECT , POHD.VENDOR_CD , GETCOMPANYNAME(POHD.GATE_CD, POHD.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , (POHD.PO_CREATE_DATE, 'YYYY-MM-DD') AS PO_CREATE_DATE , POHD.CUR , POHD.PO_AMT , POHD.VAT_TYPE , POHD.DELIVERY_TYPE , POHD.PAY_TYPE , POHD.CTRL_CD , POHD.CTRL_USER_ID , GETUSERNAME(POHD.GATE_CD, POHD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , POHD.BUYER_CD , GETCOMPANYNAME(POHD.GATE_CD, POHD.BUYER_CD, #{ses.langCd}) AS BUYER_NM , POHD.DEPT_CD , GETDEPTNAME(POHD.GATE_CD, POHD.BUYER_CD, POHD.DEPT_CD, #{ses.langCd}) AS DEPT_NM , GETBUYERDEPTNAME(POHD.GATE_CD, POHD.BUYER_CD, POHD.DEPT_CD, #{ses.langCd}) AS BUYER_DEPT_NM , POHD.PO_CREATE_TYPE , POHD.RMK_TEXT_NUM , POHD.ATT_FILE_NUM , POHD.INSPECT_USER_ID , GETUSERNAME(POHD.GATE_CD, POHD.INSPECT_USER_ID, #{ses.langCd}) AS INSPECT_USER_NM , POHD.APP_DOC_NUM , POHD.APP_DOC_CNT , POHD.PROGRESS_CD , POHD.SIGN_STATUS ,(SELECT MAX(EXEC_NUM) FROM STOCPODT WHERE GATE_CD = POHD.GATE_CD AND BUYER_CD = POHD.BUYER_CD AND PO_NUM = POHD.PO_NUM AND DEL_FLAG = '0') AS EXEC_NUM FROM STOCPOHD POHD WHERE POHD.GATE_CD = #{ses.gateCd}
AND POHD.BUYER_CD = #{BUYER_CD}
AND POHD.BUYER_CD = #{ses.companyCd}
AND POHD.PO_NUM = #{PO_NUM}
AND POHD.APP_DOC_NUM = #{APP_DOC_NUM}
AND POHD.DEL_FLAG = '0'

